from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

# Dinh nghia kieu du lieu yeu cau su dung Pydantic
class Item(BaseModel):
    name: str
    price: float
    is_offer: bool = None

# Route trich xuat ca Path Parameter, Query Parameter va Request Body
@app.post("/items/{item_id}")
def create_item(item_id: int, q: str = None, item: Item = None):
    result = {"item_id": item_id}
    if q:
        result.update({"query_search": q})
    if item:
        result.update({"item_data": item.dict()})
    return result

