import os
from fastapi import FastAPI, HTTPException, Request, status
from fastapi.responses import JSONResponse
import uvicorn

app = FastAPI()

# Định nghĩa ngoại lệ tùy chỉnh
class OutOfStockException(Exception):
    def __init__(self, product_name: str):
        self.product_name = product_name

# Tùy chỉnh bộ xử lý ngoại lệ (Custom Exception Handler)
@app.exception_handler(OutOfStockException)
async def out_of_stock_handler(request: Request, exc: OutOfStockException):
    return JSONResponse(
        status_code=status.HTTP_400_BAD_REQUEST,
        content={"error": "OUT_OF_STOCK", "detail": f"Sản phẩm '{exc.product_name}' hiện đã hết hàng."}
    )

@app.get("/checkout/{product_id}")
async def checkout(product_id: int):
    if product_id <= 0:
        raise HTTPException(status_code=400, detail="ID sản phẩm không hợp lệ.")
    if product_id == 99:
        raise OutOfStockException(product_name="Laptop Pro Max")
    return {"product_id": product_id, "status": "order_placed"}

if __name__ == "__main__":
    # Lấy thông tin Host và Port từ biến môi trường
    host = os.getenv("SERVER_HOST", "127.0.0.1")
    port = int(os.getenv("SERVER_PORT", 8000))
    uvicorn.run("main:app", host=host, port=port, reload=True)

