from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from fastapi.exceptions import HTTPException

app = FastAPI()

# Thiết lập Exception Handler để chuẩn hóa tất cả HTTPException phát sinh
@app.exception_handler(HTTPException)
def custom_http_exception_handler(request: Request, exc: HTTPException):
    return JSONResponse(
        status_code=exc.status_code,
        content={
            "status": "error",
            "message": exc.detail,
            "data": None,
            "error": {
                "code": exc.status_code,
                "details": "HTTP exception occurred"
            }
        }
    )

# Hàm helper để định dạng nhanh phản hồi thành công
def format_success_response(data: any, message: str = "Thao tác thành công"):
    return {
        "status": "success",
        "message": message,
        "data": data,
        "error": None
    }

@app.get("/items/{item_id}")
def read_item(item_id: int):
    if item_id <= 0:
        raise HTTPException(status_code=400, detail="ID sản phẩm không hợp lệ")
    return format_success_response(data={"item_id": item_id, "name": "Sách giáo trình FastAPI"})

