from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from datetime import datetime

app = FastAPI()

# Định nghĩa một Custom Exception tùy biến
class DatabaseConnectionException(Exception):
    def __init__(self, message: str):
        self.message = message

# Đăng ký Global Exception Handler để bắt lỗi DatabaseConnectionException toàn cục
@app.exception_handler(DatabaseConnectionException)
def database_exception_handler(request: Request, exc: DatabaseConnectionException):
    return JSONResponse(
        status_code=500,
        content={
            "success": False,
            "error_code": "DB_CONN_FAILURE",
            "message": exc.message,
            "timestamp": datetime.utcnow().isoformat()
        }
    )

@app.get("/test-db")
def test_db():
    # Giả lập tình huống lỗi hệ thống kết nối cơ sở dữ liệu bị mất
