def check_blacklist_old(users, target_user):
    is_blocked = False
    for user in users:
        if user["name"] == target_user:
            if user["is_blocked"]:
                is_blocked = True
                break

    if is_blocked:
        return "Người dùng bị chặn"
    else:
        return "Người dùng hợp lệ"

# Hàm sau khi refactor bằng cách sử dụng loop-else
def check_blacklist_new(users, target_user):
    for user in users:
        if user["name"] == target_user:
            if user["is_blocked"]:
                return "Người dùng bị chặn"
            break
    else:
        # Khối else chạy khi không tìm thấy user hoặc không thỏa mãn điều kiện block
        return "Người dùng hợp lệ"

